import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [published, setPublished] = useState(false);

  const handlePublish = () => {
    setPublished(true);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 w-96">
        <h2 className="text-xl font-bold mb-4">Post Editor</h2>
        <input
          type="text"
          className="mb-4 w-full p-2 text-lg text-gray-700"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="Title"
        />

        <textarea
          className="mb-4 w-full h-40 p-2 text-lg text-gray-700"
          value={body}
          onChange={(e) => setBody(e.target.value)}
          placeholder="Body"
        />

        <button
          className="bg-[#C06C88] hover:bg-[#411C56] text-white font-bold py-2 px-4 rounded"
          onClick={handlePublish}
        >
          Publish
        </button>
      </div>
    </div>
  );
};

export default App;
